{
  "name": "SpiritScribe - Instant Sermon Summaries",
  "description": "Your Faithful Note-Taking App: Turn any sermon audio/video/live speech into clean notes, key points, detected scriptures, action steps, devotional recaps, and shareable content, all automatically.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { Layout } from './components/Layout';
import { Button } from './components/Button';
import { AudioRecorder } from './components/AudioRecorder';
import { SermonSummary } from './components/SermonSummary';
import { processSermonTranscript } from './services/geminiService';
import { SermonSummaryOutput } from './types';

type AppScreen = 'home' | 'listening' | 'summary' | 'upload';

function App() {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>('home');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [sermonOutput, setSermonOutput] = useState<SermonSummaryOutput | null>(null);
  const [includeReflection, setIncludeReflection] = useState<boolean>(false);

  const handleProcessTranscript = useCallback(async (transcript: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await processSermonTranscript(transcript, includeReflection);
      setSermonOutput(result);
      setCurrentScreen('summary');
    } catch (err: any) {
      console.error("Error processing sermon:", err);
      setError(err.message || "Failed to process sermon. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [includeReflection]);

  const handleToggleReflection = useCallback(() => {
    setIncludeReflection(prev => !prev);
  }, []);

  const handleGoHome = useCallback(() => {
    setCurrentScreen('home');
    setSermonOutput(null);
    setError(null);
    setIncludeReflection(false);
  }, []);

  const renderScreen = () => {
    switch (currentScreen) {
      case 'home':
        return (
          <div className="flex flex-col items-center justify-center space-y-6 text-center">
            <h1 className="text-4xl md:text-5xl font-extrabold text-blue-800">SpiritScribe</h1>
            <p className="text-xl text-gray-700 max-w-2xl">
              Turn any sermon into organized spiritual notes instantly. Focus on worship, we'll handle the notes.
            </p>
            <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-4">
              <Button onClick={() => setCurrentScreen('listening')} className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105">
                🎙️ Start Live Listen
              </Button>
              <Button onClick={() => setCurrentScreen('upload')} className="bg-white text-blue-600 border-2 border-blue-400 hover:border-blue-600 hover:bg-blue-50 font-bold py-3 px-8 rounded-full shadow-md transition-all duration-300 transform hover:scale-105">
                ☁️ Upload Sermon
              </Button>
            </div>
            <p className="text-sm text-gray-500 mt-4">
              <span className="font-semibold">Note:</span> Live Listen mode requires microphone access.
            </p>
          </div>
        );
      case 'listening':
        return (
          <AudioRecorder
            onStopRecording={handleProcessTranscript}
            onCancel={() => setCurrentScreen('home')}
            isLoading={isLoading}
            error={error}
          />
        );
      case 'upload':
        return (
          <UploadSermon
            onProcessTranscript={handleProcessTranscript}
            onCancel={() => setCurrentScreen('home')}
            isLoading={isLoading}
            error={error}
          />
        );
      case 'summary':
        return sermonOutput ? (
          <SermonSummary
            summary={sermonOutput}
            onGoHome={handleGoHome}
            includeReflection={includeReflection}
            onToggleReflection={handleToggleReflection}
            isLoading={isLoading} // Pass loading state for potential re-processing with reflection
          />
        ) : (
          <div className="flex flex-col items-center justify-center min-h-screen p-4 text-center">
            <p className="text-lg text-red-600">No sermon summary available. Please go back and process a sermon.</p>
            <Button onClick={handleGoHome} className="mt-6 bg-red-500 hover:bg-red-600 text-white font-bold py-2 px-6 rounded-full shadow-md">
              Go Home
            </Button>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <Layout>
      {renderScreen()}
      {error && (
        <div className="fixed bottom-4 left-1/2 -translate-x-1/2 bg-red-600 text-white p-3 rounded-lg shadow-xl animate-fade-in-up z-50">
          {error}
        </div>
      )}
    </Layout>
  );
}

interface UploadSermonProps {
  onProcessTranscript: (transcript: string) => Promise<void>;
  onCancel: () => void;
  isLoading: boolean;
  error: string | null;
}

const UploadSermon: React.FC<UploadSermonProps> = ({ onProcessTranscript, onCancel, isLoading, error }) => {
  const [transcriptText, setTranscriptText] = useState<string>('');
  const [isProcessing, setIsProcessing] = useState<boolean>(false);

  const handleProcess = async () => {
    if (!transcriptText.trim()) {
      alert('Please paste a sermon transcript to proceed.');
      return;
    }
    setIsProcessing(true);
    await onProcessTranscript(transcriptText);
    setIsProcessing(false);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen-70vh p-4 bg-gray-50">
      <div className="w-full max-w-3xl bg-white rounded-lg shadow-2xl p-8 transform transition-all duration-300 ease-in-out hover:shadow-3xl">
        <h2 className="text-3xl font-bold text-center text-blue-800 mb-6">Upload Sermon Transcript</h2>
        <p className="text-gray-700 text-center mb-8">
          Paste the text of your sermon transcript below. For now, direct audio/video link processing is under development.
        </p>

        <textarea
          className="w-full h-64 p-4 mb-6 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200 resize-y text-gray-800 leading-relaxed text-base"
          placeholder="Paste your sermon transcript here..."
          value={transcriptText}
          onChange={(e) => setTranscriptText(e.target.value)}
          disabled={isLoading || isProcessing}
        ></textarea>

        <div className="flex flex-col sm:flex-row justify-center space-y-4 sm:space-y-0 sm:space-x-4">
          <Button
            onClick={handleProcess}
            disabled={isLoading || isProcessing || !transcriptText.trim()}
            className="w-full sm:w-auto bg-gradient-to-r from-green-500 to-teal-600 hover:from-green-600 hover:to-teal-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
          >
            {isLoading || isProcessing ? 'Processing...' : 'Process Transcript'}
          </Button>
          <Button
            onClick={onCancel}
            disabled={isLoading || isProcessing}
            className="w-full sm:w-auto bg-white text-gray-700 border-2 border-gray-300 hover:border-gray-500 hover:bg-gray-100 font-bold py-3 px-8 rounded-full shadow-md transition-all duration-300 transform hover:scale-105"
          >
            Cancel
          </Button>
        </div>

        {error && (
          <p className="text-red-500 text-center mt-4">{error}</p>
        )}
      </div>
    </div>
  );
};


export default App;

export interface Scripture {
  reference: string;
  plain_meaning: string;
  speaker_usage: string;
}

export interface Reflection {
  takeaway: string;
  reflection_text: string;
  prayer: string;
}

export interface SermonSummaryOutput {
  title: string;
  main_topic: string;
  clean_transcript: string;
  scriptures: Scripture[];
  key_points: string[];
  quotes: string[];
  applications: string[];
  open_questions: string[];
  reflection?: Reflection; // Optional as it depends on user flag
}

export interface TabProps {
  summary: SermonSummaryOutput;
}

import { GoogleGenAI } from "@google/genai";
import { MASTER_SERMON_PROCESSING_PROMPT } from '../constants';
import { SermonSummaryOutput } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const GEMINI_MODEL = 'gemini-3-pro-preview'; // For complex text tasks

export async function processSermonTranscript(
  transcript: string,
  includeReflection: boolean,
): Promise<SermonSummaryOutput> {
  if (!process.env.API_KEY) {
    throw new Error("Gemini API Key is not configured. Please set process.env.API_KEY.");
  }

  const prompt = MASTER_SERMON_PROCESSING_PROMPT(transcript, includeReflection);

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        // Using a higher thinkingBudget for complex summarization, ensure it doesn't exceed model limits.
        thinkingConfig: { thinkingBudget: 8000 }, 
      },
    });

    const jsonString = response.text?.trim();

    if (!jsonString) {
      throw new Error("No response or empty response from Gemini API.");
    }

    // Attempt to parse the JSON, handling potential leading/trailing markdown
    let parsedData: SermonSummaryOutput;
    try {
      // Remove potential markdown code block fences
      const cleanJsonString = jsonString.startsWith('```json') && jsonString.endsWith('```')
        ? jsonString.substring(7, jsonString.length - 3).trim()
        : jsonString;
      parsedData = JSON.parse(cleanJsonString);
    } catch (parseError) {
      console.error("Failed to parse JSON response:", jsonString, parseError);
      throw new Error(`Invalid JSON response from AI: ${jsonString.substring(0, 200)}...`);
    }

    // Ensure reflection is an empty object if it's not truly generated
    if (!includeReflection && parsedData.reflection && Object.keys(parsedData.reflection).length > 0) {
      // If reflection was not requested but the model still generated some content,
      // it's an unexpected behavior, but for safety, we can clear it or log a warning.
      // For this app, we'll respect the includeReflection flag strictly.
      parsedData.reflection = {};
    } else if (includeReflection && !parsedData.reflection) {
        // If reflection was requested but not generated, initialize to empty for consistency
        parsedData.reflection = {};
    }

    return parsedData;

  } catch (error: any) {
    console.error("Error calling Gemini API:", error);
    if (error.response && error.response.error) {
      throw new Error(`Gemini API Error: ${error.response.error.message} (Code: ${error.response.error.code})`);
    }
    throw new Error(`Failed to communicate with Gemini API: ${error.message}`);
  }
}

