import React, { useState, useCallback, useEffect } from 'react';
import { SermonSummaryOutput } from '../types';
import { Button } from './Button';
import { TranscriptTab } from './TranscriptTab';
import { ScripturesTab } from './ScripturesTab';
import { ApplyTab } from './ApplyTab';
import { processSermonTranscript } from '../services/geminiService'; // Import for re-processing

interface SermonSummaryProps {
  summary: SermonSummaryOutput;
  onGoHome: () => void;
  includeReflection: boolean;
  onToggleReflection: () => void;
  isLoading: boolean;
}

type SummaryTab = 'transcript' | 'scriptures' | 'apply';

export const SermonSummary: React.FC<SermonSummaryProps> = ({
  summary,
  onGoHome,
  includeReflection,
  onToggleReflection,
  isLoading,
}) => {
  const [activeTab, setActiveTab] = useState<SummaryTab>('transcript');
  const [currentSummary, setCurrentSummary] = useState<SermonSummaryOutput>(summary);
  const [reflectionProcessing, setReflectionProcessing] = useState<boolean>(false);
  const [reflectionError, setReflectionError] = useState<string | null>(null);

  useEffect(() => {
    setCurrentSummary(summary);
  }, [summary]);

  const handleToggleReflectionAndReprocess = useCallback(async () => {
    onToggleReflection(); // Update parent state first

    setReflectionProcessing(true);
    setReflectionError(null);
    try {
      // Reprocess the *original* transcript with the new reflection flag
      // Assuming a mechanism to retrieve the original transcript, for now, we'll use a placeholder
      // In a real app, you would store the original transcript or have an API to re-process.
      const originalTranscript = currentSummary.clean_transcript; // Use the cleaned transcript for re-processing
      const updatedSummary = await processSermonTranscript(originalTranscript, !includeReflection);
      setCurrentSummary(updatedSummary);
    } catch (err: any) {
      console.error("Error re-processing for reflection:", err);
      setReflectionError(err.message || "Failed to update reflection. Please try again.");
      // Revert the toggle if re-processing fails
      onToggleReflection();
    } finally {
      setReflectionProcessing(false);
    }
  }, [currentSummary, includeReflection, onToggleReflection]);

  const renderTabContent = useCallback(() => {
    switch (activeTab) {
      case 'transcript':
        return <TranscriptTab summary={currentSummary} />;
      case 'scriptures':
        return <ScripturesTab summary={currentSummary} />;
      case 'apply':
        return <ApplyTab summary={currentSummary} />;
      default:
        return null;
    }
  }, [activeTab, currentSummary]);

  return (
    <div className="flex flex-col items-center justify-center p-4 bg-gray-50 min-h-screen-70vh">
      <div className="w-full max-w-4xl bg-white rounded-xl shadow-2xl p-10 transform transition-all duration-500 ease-in-out hover:shadow-3xl border border-gray-100">
        <h2 className="text-5xl font-extrabold text-blue-900 mb-3 text-center">{currentSummary.title || 'Sermon Summary'}</h2>
        <p className="text-xl text-gray-600 mb-8 text-center italic">{currentSummary.main_topic}</p>

        <div className="flex flex-wrap justify-center gap-4 mb-8 border-b-2 border-gray-200 pb-4">
          <button
            onClick={() => setActiveTab('transcript')}
            className={`py-3 px-8 rounded-full font-semibold transition-all duration-300 ease-in-out ${activeTab === 'transcript' ? 'bg-blue-700 text-white shadow-lg' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-800'}`}
          >
            Transcript
          </button>
          <button
            onClick={() => setActiveTab('scriptures')}
            className={`py-3 px-8 rounded-full font-semibold transition-all duration-300 ease-in-out ${activeTab === 'scriptures' ? 'bg-blue-700 text-white shadow-lg' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-800'}`}
          >
            Scriptures Explained
          </button>
          <button
            onClick={() => setActiveTab('apply')}
            className={`py-3 px-8 rounded-full font-semibold transition-all duration-300 ease-in-out ${activeTab === 'apply' ? 'bg-blue-700 text-white shadow-lg' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-800'}`}
          >
            Apply to My Life
          </button>
        </div>

        <div className="summary-content min-h-[400px] bg-blue-50 p-8 rounded-xl shadow-inner mb-8 border border-blue-100 overflow-y-auto max-h-[700px]">
          {renderTabContent()}
        </div>

        <div className="flex flex-col sm:flex-row items-center justify-between mt-8 space-y-4 sm:space-y-0">
          <label className="flex items-center cursor-pointer text-gray-700 font-medium">
            <div className="relative">
              <input
                type="checkbox"
                className="sr-only"
                checked={includeReflection}
                onChange={handleToggleReflectionAndReprocess}
                disabled={reflectionProcessing || isLoading}
              />
              <div className={`block bg-gray-300 w-14 h-8 rounded-full transition-colors duration-300 ${includeReflection ? 'bg-blue-600' : ''}`}></div>
              <div className={`dot absolute left-1 top-1 bg-white w-6 h-6 rounded-full transition-transform duration-300 ${includeReflection ? 'translate-x-full border-blue-600' : 'border-gray-300'}`}></div>
            </div>
            <span className="ml-3 text-lg">Include Reflection</span>
          </label>

          {(reflectionProcessing || isLoading) && (
            <p className="text-blue-600 text-center font-semibold animate-pulse">
              {reflectionProcessing ? 'Updating Reflection...' : 'Processing...'}
            </p>
          )}

          {reflectionError && (
            <p className="text-red-500 text-sm text-center">{reflectionError}</p>
          )}

          <Button
            onClick={onGoHome}
            className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
          >
            Process Another Sermon
          </Button>
        </div>
      </div>
    </div>
  );
};

