import { initializeApp } from 'firebase/app';
import { getAuth, createUserWithEmailAndPassword, signInWithEmailAndPassword, signOut, User } from 'firebase/auth';

// Your web app's Firebase configuration
// These values would typically come from environment variables in a real project
const firebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY || 'YOUR_FIREBASE_API_KEY', // Replace with actual key or ensure env var is set
  authDomain: process.env.FIREBASE_AUTH_DOMAIN || 'YOUR_FIREBASE_AUTH_DOMAIN',
  projectId: process.env.FIREBASE_PROJECT_ID || 'YOUR_FIREBASE_PROJECT_ID',
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET || 'YOUR_FIREBASE_STORAGE_BUCKET',
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID || 'YOUR_FIREBASE_MESSAGING_SENDER_ID',
  appId: process.env.FIREBASE_APP_ID || 'YOUR_FIREBASE_APP_ID',
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);

export const signUpUser = async (email: string, password: string): Promise<User> => {
  try {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    return userCredential.user;
  } catch (error: any) {
    console.error("Error signing up:", error);
    throw new Error(error.message || "Failed to sign up.");
  }
};

export const signInUser = async (email: string, password: string): Promise<User> => {
  try {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    return userCredential.user;
  } catch (error: any) {
    console.error("Error signing in:", error);
    throw new Error(error.message || "Failed to sign in.");
  }
};

export const signOutUser = async (): Promise<void> => {
  try {
    await signOut(auth);
  } catch (error: any) {
    console.error("Error signing out:", error);
    throw new Error(error.message || "Failed to sign out.");
  }
};

import React, { useState } from 'react';
import { Button } from './Button';
import { signInUser, signUpUser } from '../services/firebaseService';
import { User } from 'firebase/auth';

interface AuthScreenProps {
  onAuthSuccess: (user: User) => void;
  authError: string | null;
  setAuthError: (error: string | null) => void;
}

export const AuthScreen: React.FC<AuthScreenProps> = ({ onAuthSuccess, authError, setAuthError }) => {
  const [email, setEmail] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [isLoginMode, setIsLoginMode] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(false);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null); // Clear previous errors
    setIsLoading(true);

    if (!email.trim() || !password.trim()) {
      setAuthError("Email and password cannot be empty.");
      setIsLoading(false);
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setAuthError("Please enter a valid email address.");
      setIsLoading(false);
      return;
    }

    if (password.length < 6) {
      setAuthError("Password must be at least 6 characters long.");
      setIsLoading(false);
      return;
    }

    try {
      let user: User;
      if (isLoginMode) {
        user = await signInUser(email, password);
      } else {
        user = await signUpUser(email, password);
      }
      onAuthSuccess(user);
    } catch (error: any) {
      console.error("Authentication error:", error);
      setAuthError(error.message || "Authentication failed. Please check your credentials.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen-70vh p-4 bg-gray-50">
      <div className="w-full max-w-md bg-white rounded-lg shadow-2xl p-8 transform transition-all duration-300 ease-in-out hover:shadow-3xl text-center">
        <h2 className="text-3xl font-bold text-blue-800 mb-6">{isLoginMode ? 'Welcome Back!' : 'Join SpiritScribe'}</h2>
        <p className="text-gray-700 mb-8">
          {isLoginMode ? 'Log in to access your sermon summaries.' : 'Sign up to create your faithful note-taking journey.'}
        </p>

        <form onSubmit={handleAuth} className="space-y-6">
          <div>
            <input
              type="email"
              placeholder="Email"
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200 text-gray-800"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              disabled={isLoading}
              required
            />
          </div>
          <div>
            <input
              type="password"
              placeholder="Password"
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200 text-gray-800"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              disabled={isLoading}
              required
            />
          </div>

          <Button
            type="submit"
            disabled={isLoading}
            className="w-full bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
          >
            {isLoading ? 'Processing...' : (isLoginMode ? 'Log In' : 'Sign Up')}
          </Button>
        </form>

        {authError && (
          <p className="text-red-500 text-center mt-4">{authError}</p>
        )}

        <p className="mt-8 text-gray-600">
          {isLoginMode ? "Don't have an account?" : "Already have an account?"}{' '}
          <button
            onClick={() => {
              setIsLoginMode(prev => !prev);
              setAuthError(null);
              setEmail('');
              setPassword('');
            }}
            disabled={isLoading}
            className="text-blue-600 hover:text-blue-800 font-semibold transition-colors duration-200"
          >
            {isLoginMode ? 'Sign Up' : 'Log In'}
          </button>
        </p>
      </div>
    </div>
  );
};

