type AppScreen = 'home' | 'listening' | 'summary' | 'upload';

function App() {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>('home');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [sermonOutput, setSermonOutput] = useState<SermonSummaryOutput | null>(null);
  const [includeReflection, setIncludeReflection] = useState<boolean>(false);

  // Auth states
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState<boolean>(true); // Initially true while checking auth status
  const [authError, setAuthError] = useState<string | null>(null);

  useEffect(() => {
    // Listen for authentication state changes
