import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Button } from './Button';

interface AudioRecorderProps {
  onStopRecording: (transcript: string) => Promise<void>;
  onCancel: () => void;
  isLoading: boolean;
  error: string | null;
}

export const AudioRecorder: React.FC<AudioRecorderProps> = ({ onStopRecording, onCancel, isLoading, error }) => {
  const [isRecording, setIsRecording] = useState<boolean>(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);
  const [recordingDuration, setRecordingDuration] = useState<number>(0);
  const intervalRef = useRef<number | null>(null);

  const startRecording = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstart = () => {
        setIsRecording(true);
        setRecordingDuration(0);
        intervalRef.current = window.setInterval(() => {
          setRecordingDuration(prev => prev + 1);
        }, 1000);
      };

      mediaRecorder.onstop = async () => {
        setIsRecording(false);
        if (intervalRef.current) {
          window.clearInterval(intervalRef.current);
        }
        // Simulate transcription here
        console.log('Audio recording stopped. Simulating transcription...');
        const mockTranscript = `
          Good morning, everyone, and welcome to our service. It's truly a blessing to gather together today as we open God's Word. Today, we're diving into a powerful passage from Matthew chapter 6, verses 25 to 34, where Jesus teaches us about anxiety and trust. He says, "Therefore I tell you, do not worry about your life, what you will eat or drink; or about your body, what you will wear. Is not life more than food, and the body more than clothes?" This scripture reminds us that our heavenly Father knows our needs even before we ask. The birds of the air do not sow or reap or store away in barns, and yet your heavenly Father feeds them. Are you not much more valuable than they? Can any one of you by worrying add a single hour to your life?

          The main message today is to seek first God's kingdom and His righteousness, and all these things will be given to you as well. Matthew 6:33 is a cornerstone verse for us. It’s not about ignoring our responsibilities, but about shifting our ultimate reliance from ourselves to God. We often worry about what we can control, but true peace comes from surrendering what we cannot. As the old hymn says, "What a friend we have in Jesus, all our sins and griefs to bear! What a privilege to carry everything to God in prayer!" This quote highlights the power of prayer in handing over our anxieties.

          So, how can we apply this? First, pray before reacting. When anxiety strikes, bring it to God. Second, trust God before understanding. We don't need all the answers to trust His character. Third, live one day at a time. Jesus specifically says, "Therefore do not worry about tomorrow, for tomorrow will worry about itself. Each day has enough trouble of its own." (Matthew 6:34).

          One unanswered question for many might be, "How do I genuinely stop worrying when circumstances are truly difficult?" The speaker did not clarify this point in detail, but emphasized faith. Let us reflect on this, brothers and sisters, and allow the Holy Spirit to guide us.
        `;
        await onStopRecording(mockTranscript.trim());

        // Stop all tracks on the stream
        if (streamRef.current) {
          streamRef.current.getTracks().forEach(track => track.stop());
        }
      };

      mediaRecorder.start();
    } catch (err) {
      console.error('Error starting recording:', err);
      alert('Could not start recording. Please ensure microphone access is granted.');
      setIsRecording(false);
      if (intervalRef.current) {
        window.clearInterval(intervalRef.current);
      }
    }
  }, [onStopRecording]);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
  }, [isRecording]);

  // Clean up on component unmount
  useEffect(() => {
    return () => {
      if (mediaRecorderRef.current && isRecording) {
        mediaRecorderRef.current.stop();
      }
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      if (intervalRef.current) {
        window.clearInterval(intervalRef.current);
      }
    };
  }, [isRecording]); // Added isRecording to useEffect dependencies for cleanup reliability.

  const formatTime = (seconds: number) => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen-70vh p-4 bg-gray-50">
      <div className="w-full max-w-2xl bg-white rounded-lg shadow-2xl p-10 transform transition-all duration-300 ease-in-out hover:shadow-3xl text-center">
        <h2 className="text-4xl font-extrabold text-blue-900 mb-6">Live Listen Mode</h2>
        <p className="text-lg text-gray-700 mb-8">
          Tap "Start Recording" to capture your sermon. We'll provide a structured summary once you stop.
        </p>

        <div className="flex items-center justify-center mb-8">
          <div className={`relative w-40 h-40 rounded-full flex items-center justify-center transition-all duration-300 ${isRecording ? 'bg-red-200 animate-pulse-fade' : 'bg-gray-200'}`}>
            {isRecording && (
              <div className="absolute inset-0 rounded-full bg-red-500 opacity-20 animate-ping-slow"></div>
            )}
            <svg className="w-20 h-20 text-red-600 z-10" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
              <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0 5 5 0 01-10 0 1 1 0 10-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd"></path>
            </svg>
          </div>
        </div>

        <p className="text-2xl font-bold text-gray-800 mb-8">
          {isRecording ? `Recording... (${formatTime(recordingDuration)})` : (isLoading ? 'Transcribing & Summarizing...' : 'Ready to record')}
        </p>

        <div className="flex flex-col sm:flex-row justify-center space-y-4 sm:space-y-0 sm:space-x-4">
          {!isRecording ? (
            <Button
              onClick={startRecording}
              disabled={isLoading}
              className="w-full sm:w-auto bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
            >
              Start Recording
            </Button>
          ) : (
            <Button
              onClick={stopRecording}
              disabled={isLoading}
              className="w-full sm:w-auto bg-gradient-to-r from-green-500 to-green-600 hover:from-green-600 hover:to-green-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
            >
              Stop Recording
            </Button>
          )}
          <Button
            onClick={onCancel}
            disabled={isLoading}
            className="w-full sm:w-auto bg-white text-gray-700 border-2 border-gray-300 hover:border-gray-500 hover:bg-gray-100 font-bold py-3 px-8 rounded-full shadow-md transition-all duration-300 transform hover:scale-105"
          >
            Cancel
          </Button>
        </div>

        {error && (
          <p className="text-red-500 text-center mt-4">{error}</p>
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { SermonSummaryOutput } from '../types';
import { Button } from './Button';
import { TranscriptTab } from './TranscriptTab';
import { ScripturesTab } from './ScripturesTab';
import { ApplyTab } from './ApplyTab';
import { processSermonTranscript } from '../services/geminiService'; // Import for re-processing

interface SermonSummaryProps {
  summary: SermonSummaryOutput;
  onGoHome: () => void;
  includeReflection: boolean;
  onToggleReflection: () => void;
  isLoading: boolean;
}

type SummaryTab = 'transcript' | 'scriptures' | 'apply';

export const SermonSummary: React.FC<SermonSummaryProps> = ({
  summary,
  onGoHome,
  includeReflection,
  onToggleReflection,
  isLoading,
}) => {
  const [activeTab, setActiveTab] = useState<SummaryTab>('transcript');
  const [currentSummary, setCurrentSummary] = useState<SermonSummaryOutput>(summary);
  const [reflectionProcessing, setReflectionProcessing] = useState<boolean>(false);
  const [reflectionError, setReflectionError] = useState<string | null>(null);

  useEffect(() => {
    setCurrentSummary(summary);
  }, [summary]);

  const handleToggleReflectionAndReprocess = useCallback(async () => {
    onToggleReflection(); // Update parent state first

    setReflectionProcessing(true);
    setReflectionError(null);
    try {
      // Reprocess the *original* transcript with the new reflection flag
      // Assuming a mechanism to retrieve the original transcript, for now, we'll use a placeholder
      // In a real app, you would store the original transcript or have an API to re-process.
      const originalTranscript = currentSummary.clean_transcript; // Use the cleaned transcript for re-processing
      const updatedSummary = await processSermonTranscript(originalTranscript, !includeReflection);
      setCurrentSummary(updatedSummary);
    } catch (err: any) {
      console.error("Error re-processing for reflection:", err);
      setReflectionError(err.message || "Failed to update reflection. Please try again.");
      // Revert the toggle if re-processing fails
      onToggleReflection();
    } finally {
      setReflectionProcessing(false);
    }
  }, [currentSummary, includeReflection, onToggleReflection]);

  const renderTabContent = useCallback(() => {
    switch (activeTab) {
      case 'transcript':
        return <TranscriptTab summary={currentSummary} />;
      case 'scriptures':
        return <ScripturesTab summary={currentSummary} />;
      case 'apply':
        return <ApplyTab summary={currentSummary} />;
      default:
        return null;
    }
  }, [activeTab, currentSummary]);

  return (
    <div className="flex flex-col items-center justify-center p-4 bg-gray-50 min-h-screen-70vh">
      <div className="w-full max-w-5xl bg-white rounded-3xl shadow-3xl p-12 transform transition-all duration-500 ease-in-out hover:shadow-4xl border border-blue-100">
        <h2 className="text-5xl md:text-6xl font-extrabold text-blue-900 mb-4 text-center">{currentSummary.title || 'Sermon Summary'}</h2>
        <p className="text-xl md:text-2xl text-gray-600 mb-10 text-center italic">{currentSummary.main_topic}</p>

        <div className="flex flex-wrap justify-center gap-6 mb-10 border-b-4 border-blue-100 pb-5">
          <button
            onClick={() => setActiveTab('transcript')}
            className={`py-4 px-10 rounded-full font-bold text-lg transition-all duration-300 ease-in-out ${activeTab === 'transcript' ? 'bg-blue-800 text-white shadow-xl transform scale-105' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-900'}`}
          >
            Transcript
          </button>
          <button
            onClick={() => setActiveTab('scriptures')}
            className={`py-4 px-10 rounded-full font-bold text-lg transition-all duration-300 ease-in-out ${activeTab === 'scriptures' ? 'bg-blue-800 text-white shadow-xl transform scale-105' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-900'}`}
          >
            Scriptures Explained
          </button>
          <button
            onClick={() => setActiveTab('apply')}
            className={`py-4 px-10 rounded-full font-bold text-lg transition-all duration-300 ease-in-out ${activeTab === 'apply' ? 'bg-blue-800 text-white shadow-xl transform scale-105' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 hover:text-blue-900'}`}
          >
            Apply to My Life
          </button>
        </div>

        <div className="summary-content min-h-[500px] bg-blue-50 p-10 rounded-2xl shadow-inner-xl mb-8 border border-blue-200 overflow-y-auto max-h-[700px]">
          {renderTabContent()}
        </div>

        <div className="flex flex-col sm:flex-row items-center justify-between mt-8 space-y-4 sm:space-y-0">
          <label className="flex items-center cursor-pointer text-gray-700 font-medium">
            <div className="relative">
              <input
                type="checkbox"
                className="sr-only"
                checked={includeReflection}
                onChange={handleToggleReflectionAndReprocess}
                disabled={reflectionProcessing || isLoading}
              />
              <div className={`block bg-gray-300 w-16 h-9 rounded-full transition-colors duration-300 ${includeReflection ? 'bg-blue-700' : ''}`}></div>
              <div className={`dot absolute left-1 top-1 bg-white w-7 h-7 rounded-full transition-transform duration-300 ${includeReflection ? 'translate-x-full border-blue-700' : 'border-gray-300'}`}></div>
            </div>
            <span className="ml-3 text-xl">Include Reflection</span>
          </label>

          {(reflectionProcessing || isLoading) && (
            <p className="text-blue-700 text-center font-semibold animate-pulse text-xl">
              {reflectionProcessing ? 'Updating Reflection...' : 'Processing...'}
            </p>
          )}

          {reflectionError && (
            <p className="text-red-500 text-sm text-center">{reflectionError}</p>
          )}

          <Button
            onClick={onGoHome}
            className="bg-blue-800 hover:bg-blue-900 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all duration-300 transform hover:scale-105"
          >
            Process Another Sermon
          </Button>
        </div>
      </div>
    </div>
  );
};

